int monotoneIncreasingDigits(int N) {
    char s[16]; sprintf(s, "%d", N);
    int n = strlen(s);
    for (int i = n - 1; i > 0; i--)
        if (s[i] < s[i-1]) {
            s[i-1]--;
            for (int j = i; j < n; j++) s[j] = '9';
        }
    return atoi(s);
}
